        return self as? DBXTeamLogFileCommentNotificationPolicyEnabled
    }

    @objc
    public var asOther: DBXTeamLogFileCommentNotificationPolicyOther? {
        return self as? DBXTeamLogFileCommentNotificationPolicyOther
    }
}

