/// An audit log event.
@objc
public class DBXTeamLogTeamEvent: NSObject {
    /// The Dropbox timestamp representing when the action was taken.
    @objc
    public var timestamp_: Date { swift.timestamp_ }
    /// The category that this type of action belongs to.
    @objc
    public var eventCategory: DBXTeamLogEventCategory { DBXTeamLogEventCategory(swift: swift.eventCategory) }
    /// The entity who actually performed the action.
    @objc
    public var actor: DBXTeamLogActorLogInfo? { guard let swift = swift.actor else { return nil }; return DBXTeamLogActorLogInfo(swift: swift) }
    /// The origin from which the actor performed the action including information about host, ip address, location,
    /// session, etc. If the action was performed programmatically via the API the origin represents the API
    /// client.
    @objc
    public var origin: DBXTeamLogOriginLogInfo? { guard let swift = swift.origin else { return nil }; return DBXTeamLogOriginLogInfo(swift: swift) }
    /// True if the action involved a non team member either as the actor or as one of the affected users.
    @objc
    public var involveNonTeamMember: NSNumber? { swift.involveNonTeamMember as NSNumber? }
    /// The user or team on whose behalf the actor performed the action.
    @objc
    public var context: DBXTeamLogContextLogInfo? { guard let swift = swift.context else { return nil }; return DBXTeamLogContextLogInfo(swift: swift) }
    /// Zero or more users and/or groups that are affected by the action. Note that this list doesn't include any
    /// actors or users in context.
    @objc
    public var participants: Array<DBXTeamLogParticipantLogInfo>? { swift.participants?.map { DBXTeamLogParticipantLogInfo(swift: $0) } }
    /// Zero or more content assets involved in the action. Currently these include Dropbox files and folders but in
    /// the future we might add other asset types such as Paper documents, folders, projects, etc.
    @objc
    public var assets: Array<DBXTeamLogAssetLogInfo>? { swift.assets?.map { DBXTeamLogAssetLogInfo(swift: $0) } }
    /// The particular type of action taken.
    @objc
    public var eventType: DBXTeamLogEventType { DBXTeamLogEventType(swift: swift.eventType) }
    /// The variable event schema applicable to this type of action, instantiated with respect to this particular
    /// action.
    @objc
    public var details: DBXTeamLogEventDetails { DBXTeamLogEventDetails(swift: swift.details) }

    @objc
    public init(timestamp_: Date, eventCategory: DBXTeamLogEventCategory, eventType: DBXTeamLogEventType, details: DBXTeamLogEventDetails, actor: DBXTeamLogActorLogInfo?, origin: DBXTeamLogOriginLogInfo?, involveNonTeamMember: NSNumber?, context: DBXTeamLogContextLogInfo?, participants: Array<DBXTeamLogParticipantLogInfo>?, assets: Array<DBXTeamLogAssetLogInfo>?) {
        self.swift = TeamLog.TeamEvent(timestamp_: timestamp_, eventCategory: eventCategory.swift, eventType: eventType.swift, details: details.swift, actor: actor?.swift, origin: origin?.swift, involveNonTeamMember: involveNonTeamMember?.boolValue, context: context?.swift, participants: participants?.map { $0.swift }, assets: assets?.map { $0.swift })
    }

    let swift: TeamLog.TeamEvent

    public init(swift: TeamLog.TeamEvent) {
        self.swift = swift
    }


    @objc
    public override var description: String { swift.description }
}

